describe('pipeline/plugins/treesitter/runtime/analyze/goImports', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('resolves absolute and relative imports and stores bindings by alias or package name', () => {
    const relativePathNode = { type: 'interpreted_string_literal', text: '"./internal/helper"' };
    const absolutePathNode = { type: 'interpreted_string_literal', text: '"github.com/acme/widget"' };
    const missingPathNode = { type: 'interpreted_string_literal', text: '""' };
    const relativeImport = createNode({
      childForFieldName: (name: string) => {
        expect(['path', 'name']).toContain(name);
        return name === 'path' ? relativePathNode : null;
      },
    });
    const absoluteImport = createNode({
      childForFieldName: (name: string) => {
        expect(['path', 'name']).toContain(name);
        return name === 'path' ? absolutePathNode : name === 'name' ? { type: 'identifier', text: 'widget' } : null;
      },
    });
    const missingImport = createNode({
      childForFieldName: (name: string) => {
        expect(['path', 'name']).toContain(name);
        return name === 'path' ? missingPathNode : null;
      },
    });
    vi.mocked(getStringSpecifier)
      .mockReturnValueOnce('./internal/helper')
      .mockReturnValueOnce('github.com/acme/widget')
      .mockReturnValueOnce(null);
    vi.mocked(getIdentifierText).mockReturnValueOnce(null).mockReturnValueOnce('widget');
    vi.mocked(resolveTreeSitterImportPath).mockReturnValue('/workspace/internal/helper.go');
    vi.mocked(resolveGoPackagePath).mockReturnValue('/workspace/pkg/mod/github.com/acme/widget');

    const relations: never[] = [];
    const importedBindings = new Map();

    expect(
      handleGoImportDeclaration(
        createNode({
          descendantsOfType: (type: string) => {
            expect(type).toBe('import_spec');
            return [relativeImport, absoluteImport, missingImport];
          },
        }) as never,
        '/workspace/cmd/app/main.go',
        '/workspace',
        relations,
        importedBindings as never,
      ),
    ).toEqual({ skipChildren: true });
    expect(resolveTreeSitterImportPath).toHaveBeenCalledWith('/workspace/cmd/app/main.go', './internal/helper');
    expect(resolveGoPackagePath).toHaveBeenCalledWith(
      '/workspace/cmd/app/main.go',
      '/workspace',
      'github.com/acme/widget',
    );
    expect(addImportRelation).toHaveBeenNthCalledWith(
      1,
      relations,
      '/workspace/cmd/app/main.go',
      './internal/helper',
      '/workspace/internal/helper.go',
    );
    expect(addImportRelation).toHaveBeenNthCalledWith(
      2,
      relations,
      '/workspace/cmd/app/main.go',
      'github.com/acme/widget',
      '/workspace/pkg/mod/github.com/acme/widget',
    );
    expect(importedBindings.get('helper')).toEqual({
      importedName: './internal/helper',
      resolvedPath: '/workspace/internal/helper.go',
      specifier: './internal/helper',
    });
    expect(importedBindings.get('widget')).toEqual({
      importedName: 'github.com/acme/widget',
      resolvedPath: '/workspace/pkg/mod/github.com/acme/widget',
      specifier: 'github.com/acme/widget',
    });
    expect(getLastPathSegment).toHaveBeenCalledWith('./internal/helper', '/');
  });

  it('prefers an explicit alias name over the package basename', () => {
    const aliasImport = createNode({
      childForFieldName: (name: string) => {
        expect(['path', 'name']).toContain(name);
        return name === 'path'
          ? { type: 'interpreted_string_literal', text: '"github.com/acme/widget"' }
          : { type: 'identifier', text: 'aliasWidget' };
      },
    });
    vi.mocked(getStringSpecifier).mockReturnValue('github.com/acme/widget');
    vi.mocked(getIdentifierText).mockReturnValue('aliasWidget');
    vi.mocked(resolveGoPackagePath).mockReturnValue('/workspace/pkg/mod/github.com/acme/widget');

    const importedBindings = new Map();

    handleGoImportDeclaration(
      createNode({
        descendantsOfType: (type: string) => {
          expect(type).toBe('import_spec');
          return [aliasImport];
        },
      }) as never,
      '/workspace/cmd/app/main.go',
      '/workspace',
      [] as never[],
      importedBindings as never,
    );

    expect(importedBindings.get('aliasWidget')).toEqual({
      importedName: 'github.com/acme/widget',
      resolvedPath: '/workspace/pkg/mod/github.com/acme/widget',
      specifier: 'github.com/acme/widget',
    });
    expect(getLastPathSegment).not.toHaveBeenCalled();
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { analyzeGoFile } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/go';

const {
  handleGoImportDeclaration,
  handleGoCallableDeclaration,
  handleGoTypeSpec,
  handleGoCallExpression,
  normalizeAnalysisResult,
  walkTree,
} = vi.hoisted(() => ({
  handleGoImportDeclaration: vi.fn(),
  handleGoCallableDeclaration: vi.fn(),
  handleGoTypeSpec: vi.fn(),
  handleGoCallExpression: vi.fn(),
  normalizeAnalysisResult: vi.fn(),
  walkTree: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/goImports', () => ({
  handleGoImportDeclaration,
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/goHandlers', () => ({
  handleGoCallableDeclaration,
  handleGoCallExpression,
  handleGoTypeSpec,
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/results', () => ({
  normalizeAnalysisResult,
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/walk', () => ({
  walkTree,
}));

describe('pipeline/plugins/treesitter/runtime/analyze/go', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    normalizeAnalysisResult.mockImplementation((filePath, symbols, relations) => ({
      filePath,
      symbols,
      relations,
    }));
  });

  it('routes import, callable, type, and call nodes to the matching handlers', () => {
    const rootNode = { type: 'source_file' };
    const filePath = '/workspace/main.go';
    const workspaceRoot = '/workspace';
    let visit: ((node: unknown, state: unknown, walk: unknown) => unknown) | undefined;
    walkTree.mockImplementation((_root, _state, callback) => {
      visit = callback;
    });

    analyzeGoFile(filePath, { rootNode } as never, workspaceRoot);

    const walk = vi.fn();
    const state = { currentSymbolId: 'symbol-id' };

    expect(visit?.({ type: 'import_declaration' }, state, walk)).toBeUndefined();
    expect(handleGoImportDeclaration).toHaveBeenCalledWith(
      { type: 'import_declaration' },
      filePath,
      workspaceRoot,
      expect.any(Array),
      expect.any(Map),
    );

    visit?.({ type: 'function_declaration' }, state, walk);
    visit?.({ type: 'method_declaration' }, state, walk);
    expect(handleGoCallableDeclaration).toHaveBeenNthCalledWith(
      1,
      { type: 'function_declaration' },
      filePath,
      expect.any(Array),
      walk,
    );
    expect(handleGoCallableDeclaration).toHaveBeenNthCalledWith(
      2,
      { type: 'method_declaration' },
      filePath,
      expect.any(Array),
      walk,
    );

    expect(visit?.({ type: 'type_spec' }, state, walk)).toBeUndefined();
    expect(handleGoTypeSpec).toHaveBeenCalledWith(
      { type: 'type_spec' },
      filePath,
      expect.any(Array),
    );

    expect(visit?.({ type: 'call_expression' }, state, walk)).toBeUndefined();
    expect(handleGoCallExpression).toHaveBeenCalledWith(
      { type: 'call_expression' },
      filePath,
      expect.any(Array),
      expect.any(Map),
      'symbol-id',
    );
  });

  it('ignores unknown Go node types and normalizes the collected result', () => {
    const rootNode = { type: 'source_file' };
    walkTree.mockImplementation((_root, _state, callback) => {
      expect(callback({ type: 'comment' }, {}, vi.fn())).toBeUndefined();
    });

    const result = analyzeGoFile('/workspace/main.go', { rootNode } as never, '/workspace');

    expect(handleGoImportDeclaration).not.toHaveBeenCalled();
    expect(handleGoCallableDeclaration).not.toHaveBeenCalled();
    expect(handleGoTypeSpec).not.toHaveBeenCalled();
    expect(handleGoCallExpression).not.toHaveBeenCalled();
    expect(normalizeAnalysisResult).toHaveBeenCalledWith(
      '/workspace/main.go',
      expect.any(Array),
      expect.any(Array),
    );
    expect(result).toEqual({
      filePath: '/workspace/main.go',
      symbols: [],
      relations: [],
    });
  });
});

